export function getPlacement (options, modifiers) {
  let result = options.placement
  if (!result && modifiers) {
    for (const pos of placements) {
      if (modifiers[pos]) {
        result = pos
      }
    }
  }
  if (!result) {
    result = getDefaultConfig(options.theme || 'tooltip', 'placement')
  }
  return result
}

export function install (app, options: FloatingVueConfig = {}) {
  if (app.$_vTooltipInstalled) return
  app.$_vTooltipInstalled = true

  assign(config, options)

  // Directive
  app.directive('tooltip', PrivateVTooltip)
  app.directive('close-popper', PrivateVClosePopper)
  // Components
  app.component('VTooltip', PrivateTooltip)
  app.component('VDropdown', PrivateDropdown)
  app.component('VMenu', PrivateMenu)
}

render(h, { props: suppliedProps, data, children }) {
  const { active } = suppliedProps
  const tag = active ? 'span' : BLink

  const componentData = {
    attrs: { 'aria-current': active ? suppliedProps.ariaCurrent : null },
    props: pluckProps(props, suppliedProps)
  }

  if (!children) {
    componentData.domProps = htmlOrText(suppliedProps.html, suppliedProps.text)
  }

  return h(tag, mergeData(data, componentData), children)
}

mounted() {
  // Cache current browser transitionend event name
  this.transitionEndEvent = getTransitionEndEvent(this.$el) || null
  // Get all slides
  this.updateSlides()
  // Observe child changes so we can update slide list
  this.setObserver(true)
}

setFiles(files) {
  // Reset the dragging flags
  this.dropAllowed = !this.noDrop
  this.dragging = false
  // Set the selected files
  this.files = this.multiple
    ? this.directory
      ? files
      : flattenDeep(files)
    : flattenDeep(files).slice(0, 1)
}

get props() {
  // Allow props to be lazy evaled on first access and
  // then they become a non-getter afterwards
  // https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Functions/get#Smart_self-overwriting_lazy_getters
  delete this.props
  this.props = generateProps()
  return this.props
}

(h, ctx) => {
  // We render the header even if `lazy` is enabled as it
  // acts as the accessible label for the sidebar
  const $header = renderHeader(h, ctx)
  if (ctx.lazy && !ctx.isOpen) {
    return $header
  }

  return [$header, renderBody(h, ctx), renderFooter(h, ctx)]
}

getFormattedValue(item, field) {
  const { key } = field
  const formatter = this.getFieldFormatter(key)
  let value = get(item, key, null)
  if (isFunction(formatter)) {
    value = formatter(value, key, item)
  }
  return isUndefinedOrNull(value) ? '' : value
}

timeFormatter() {
  // Returns a formatter function reference
  // The formatter converts the time to a localized string
  const options = {
    hour12: this.is12Hour,
    hourCycle: this.computedHourCycle,
    hour: NUMERIC,
    minute: NUMERIC,
    timeZone: 'UTC'
  }
  if (this.showSeconds) {
    options.second = NUMERIC
  }
  // Formats the time as a localized string
  return createDateFormatter(this.computedLocale, options)
}

templateAttributes() {
  const { id } = this

  return {
    // Apply attributes from root tooltip component
    ...this.bvParent.bvParent.$attrs,

    id,
    role: 'tooltip',
    tabindex: '-1',

    // Add the scoped style data attribute to the template root element
    ...this.scopedStyleAttrs
  }
}

render(h) {
  // This component has no root element, so only a single VNode is allowed
  if (this.disabled) {
    const $nodes = concat(this.normalizeSlot()).filter(identity)
    if ($nodes.length > 0 && !$nodes[0].text) {
      return $nodes[0]
    }
  }
  return h()
}

whileOpenListen(isOpen) {
  // Hide the dropdown when clicked outside
  this.listenForClickOut = isOpen
  // Hide the dropdown when it loses focus
  this.listenForFocusIn = isOpen
  // Hide the dropdown when another dropdown is opened
  const method = isOpen ? 'listenOnRoot' : 'listenOffRoot'
  this[method](ROOT_EVENT_NAME_SHOWN, this.rootCloseListener)
}

computedButtonVariant() {
  // Local variant preferred over group variant
  const { buttonVariant } = this
  if (buttonVariant) {
    return buttonVariant
  }
  if (this.isGroup && this.bvGroup.buttonVariant) {
    return this.bvGroup.buttonVariant
  }
  return 'secondary'
}

export function cleanupDirectiveInstance(
  el: HTMLElement & Record<string, unknown>,
  propertyName: string,
  uid: number
): void {
  const elWithProps = el as Record<string, unknown>
  const instance = (elWithProps[propertyName] as Record<string, unknown> | undefined)?.[uid] as
    | DirectiveInstanceState
    | undefined
  if (instance) {
    instance.destroying = true
    delete (elWithProps[propertyName] as Record<string, unknown>)[uid]
  }
}

toggle(active: boolean) {
    if (this.$refs.dropdown) {
        const dropdown = this.$refs.dropdown as BDropdownInstance
        dropdown.isActive = active ?? !dropdown.isActive
        if (dropdown.isActive) {
            // When opening the clockpicker, we always select the hour first
            this.isSelectingHour = true
        }
    }
}

handRotateAngle() {
    let currentAngle = this.prevAngle
    while (currentAngle < 0) currentAngle += 360
    const targetAngle = this.calcHandAngle(this.displayedValue)
    const degreesDiff = this.shortestDistanceDegrees(currentAngle, targetAngle)
    const angle = this.prevAngle + degreesDiff
    return angle
}

mounted() {
    window.addEventListener('mousemove', this.trackMouse)
    window.addEventListener('touchmove', this.trackMouse, { passive: false })
    window.addEventListener('mouseup', this.stopMouseCapture)
    window.addEventListener('touchend', this.stopMouseCapture)
}

beforeUnmount() {
    window.removeEventListener('mousemove', this.trackMouse)
    window.removeEventListener('touchmove', this.trackMouse)
    window.removeEventListener('mouseup', this.stopMouseCapture)
    window.removeEventListener('touchend', this.stopMouseCapture)
}

handler(newColor) {
    const { hue, saturation, lightness } = newColor

    window.clearTimeout(this.debounce)
    this.debounce = window.setTimeout(() => {
        this.hue = hue
        this.saturation = saturation
        this.lightness = lightness
    }, 200)
}

firstWeekOffset(year: number, dow: number, doy: number) {
    // first-week day -- which january is always in the first week (4 for iso, 1 for other)
    const fwd = 7 + dow - doy
    // first-week day local weekday -- which local weekday is fwd
    const firstJanuary = new Date(year, 0, fwd)
    const fwdlw = (7 + firstJanuary.getDay() - dow) % 7
    return -fwdlw + fwd - 1
}

newPosition() {
    if (this.position === undefined) return

    const position = this.position.split('-')
    if (position.length < 1) return

    const prefix = this.grouped
        ? 'is-grouped-'
        : 'has-addons-'

    if (this.position) return prefix + position[1]
    return undefined
}

selectRow(row: TableRow) {
    this.$emit('click', row)

    this._selectedRow = row // row must be clicked before dragging by touch
    if (this.selected === row) return
    if (!this.isRowSelectable(row)) return

    // Emit new and old row
    this.$emit('select', row, this.selected)

    // Emit new row to update user variable
    this.$emit('update:selected', row)
}

toggleDetails(obj: TableRow) {
    const found = this.isVisibleDetailRow(obj)

    if (found) {
        this.closeDetailRow(obj)
        this.$emit('details-close', obj)
    } else {
        this.openDetailRow(obj)
        this.$emit('details-open', obj)
    }

    // Syncs the detailed rows with the parent component
    this.$emit('update:openedDetailed', this.visibleDetailRows)
}

checkPredefinedDetailedRows() {
    const defaultExpandedRowsDefined = this.openedDetailed.length > 0
    if (defaultExpandedRowsDefined && !this.detailKey.length) {
        throw new Error('If you set a predefined opened-detailed, you must provide a unique key using the prop "detail-key"')
    }
}

function unmounted(el: Element) {
    // `filter` instead of `find` for compat with IE
    const instance = instances.filter((instance) => instance.el === el)[0]

    toggleEventListeners(instance, 'remove')

    // FIXME: remove instance from instances
}

export function createAbsoluteElement(el: Element): HTMLElement {
    const root = document.createElement('div')
    root.style.position = 'absolute'
    root.style.left = '0px'
    root.style.top = '0px'
    root.style.width = '100%'
    const wrapper = document.createElement('div')
    root.appendChild(wrapper)
    wrapper.appendChild(el)
    document.body.appendChild(root)
    return root
}
